import { useEffect, useState } from 'react';
import api from '../utils/api';

const ServerStatusIndicator = () => {
  const [isServerOnline, setIsServerOnline] = useState(null);

  useEffect(() => {
    const checkServerStatus = async () => {
      try {
        await api.get('/health');
        setIsServerOnline(true);
        console.log('✅ Backend server is online');
      } catch (error) {
        setIsServerOnline(false);
        console.error('❌ Backend server is offline:', error.message);
      }
    };

    checkServerStatus();
    // Check every 30 seconds
    const interval = setInterval(checkServerStatus, 30000);
    
    return () => clearInterval(interval);
  }, []);

  if (isServerOnline === null) return null;

  return (
    <div className={`fixed top-4 right-4 px-3 py-2 rounded-lg text-sm font-medium z-50 ${
      isServerOnline 
        ? 'bg-green-100 text-green-800 border border-green-200' 
        : 'bg-red-100 text-red-800 border border-red-200'
    }`}>
      {isServerOnline ? '🟢 Server Online' : '🔴 Server Offline'}
    </div>
  );
};

export default ServerStatusIndicator;
